1.post_install:
printf 'worker_processes 1;
events { worker_connections 128; }
http {
  include /etc/nginx/mime.types;
  server {
    listen %s;
    root %s/static;
    index index.html;
  }
}
' "${PORT}" "$APP_DIR" > data/nginx.conf && mkdir -p static && echo '<h1>Nginx is running</h1>' > static/index.html
